const items = $input.all();

// 1. Ordenar por fecha (más reciente primero)
items.sort((a, b) => b.json.fecha_creacion - a.json.fecha_creacion);

// 2. Agrupar por tipo
const grupos = {};

for (const item of items) {
  const tipo = item.json.tipo || "Sin tipo";

  if (!grupos[tipo]) {
    grupos[tipo] = [];
  }

  grupos[tipo].push(item.json);
}

// 3. Construir mensaje
let mensajeFinal = `Tickets:\n`;

for (const tipo in grupos) {
  mensajeFinal += `\n=== Tipo: ${tipo} ===\n`;

  for (const data of grupos[tipo]) {
    mensajeFinal += `
ID: ${data.id_ticket}
Tipo: ${data.tipo}
Prioridad: ${data.prioridad}
Descripción: ${data.descripcion}
Estado: ${data.estado}
Creado por: ${data.creado_por}
Fecha de creación: ${new Date(data.fecha_creacion * 1000).toLocaleString()}
-------------------------\n`;
  }
}

// 4. Retornar un solo item con el mensaje
return [
  {
    json: {
      mensaje: mensajeFinal
    }
  }
];

