const chatId = $('Telegram Trigger').item.json.message.chat.id;
const text = $('Telegram Trigger').item.json.message.text.toLowerCase();

// objeto resultado
let data = {
  tipo: null,
  prioridad: null,
  descripcion: null
};

// extraer datos
const tipoMatch = text.match(/tipo\s*[:\-]?\s*(.+)/);
const prioridadMatch = text.match(/prioridad\s*[:\-]?\s*(alta|media|baja)/);
const descripcionMatch = text.match(/descripcion\s*[:\-]?\s*(.+)/);

// asignar
if (tipoMatch) data.tipo = tipoMatch[1].trim();
if (prioridadMatch) data.prioridad = prioridadMatch[1].trim();
if (descripcionMatch) data.descripcion = descripcionMatch[1].trim();

// validar
let faltantes = [];
if (!data.tipo) faltantes.push("tipo");
if (!data.prioridad) faltantes.push("prioridad");
if (!data.descripcion) faltantes.push("descripcion");

if (faltantes.length > 0) {
  return [{
    json: {
      chatId,
      reply: `Faltan: ${faltantes.join(", ")}.\n\nEjemplo:\ntipo: soporte tecnico\nprioridad: alta\ndescripcion: no funciona`
    }
  }];
}

// OK
return [{
  json: {
    chatId,
    reply: "✅ Ticket registrado",
    tipo: data.tipo,
    prioridad: data.prioridad,
    descripcion: data.descripcion
  }
}];

